sql:
SELECT 
  (SELECT SUM(amount) FROM revenue) AS total_revenue,
  (SELECT COUNT(DISTINCT athlete_id) FROM attendance) AS total_participants;

SELECT a.name AS athlete_name, t.team_name
FROM athletes a
JOIN teams t ON a.team_id = t.team_id;

SELECT revenue_date
FROM revenue
WHERE amount = (SELECT MAX(amount) FROM revenue);

